  1→import { useRef, useCallback } from 'react';
  2→import { getStarColor, getStarRadius, simpleHash } from '../utils/starUtils';
  3→
  4→// ── Constants ──────────────────────────────────────────────────────────
  5→const MAX_SPEED = 12;
  6→const ACCEL = 0.25;
  7→const BRAKE = 0.15;
  8→const FRICTION = 0.985;
  9→const YAW_RATE = 0.035;
 10→const PITCH_RATE = 0.025;
 11→const PITCH_MAX = (89 * Math.PI) / 180; // 89° in radians
 12→const MIN_VIEW_Z = 0.5;
 13→const SPAWN_DIST = 800;
 14→const RECYCLE_Z = 1200;
 15→const SORT_INTERVAL = 5;
 16→const TARGET_DIST_MAX = 150;
 17→const TARGET_Z_MIN = 2;
 18→const TWO_PI = Math.PI * 2;
 19→
 20→// ── Docking constants ─────────────────────────────────────────────────
 21→const DOCKING_THRESHOLD_Z = 18;
 22→const DOCKING_CENTER_MAX = 50;
 23→const MAGNET_THRESHOLD_Z = 80;
 24→const MAGNET_STRENGTH = 0.015;
 25→const DOCK_ACCEL = 0.5;
 26→const DOCK_MAX_SPEED = 8;
 27→
 28→/** Max viewZ at which labels start fading in */
 29→export const LABEL_Z_MAX = 800;
 30→
 31→/** Export docking thresholds for external use */
 32→export { MAGNET_THRESHOLD_Z };
 33→
 34→/** Parse "#5f92ff" → { r, g, b } */
 35→const parseHex = (hex) => ({
 36→    r: parseInt(hex.slice(1, 3), 16),
 37→    g: parseInt(hex.slice(3, 5), 16),
 38→    b: parseInt(hex.slice(5, 7), 16),
 39→});
 40→
 41→/** Seeded pseudo-random from integer seed */
 42→const seededRandom = (seed) => {
 43→    let s = seed | 0;
 44→    return () => {
 45→        s = (s * 1664525 + 1013904223) | 0;
 46→        return ((s >>> 0) / 4294967296);
 47→    };
 48→};
 49→
 50→/** Get forward direction vector from yaw + pitch */
 51→const getForwardVector = (yaw, pitch) => ({
 52→    x: Math.sin(yaw) * Math.cos(pitch),
 53→    y: Math.sin(pitch),
 54→    z: Math.cos(yaw) * Math.cos(pitch),
 55→});
 56→
 57→const useRocketMode = () => {
 58→    const isActiveRef = useRef(false);
 59→    const camPosRef = useRef({ x: 0, y: 0, z: 0 });
 60→    const yawRef = useRef(0);
 61→    const pitchRef = useRef(0);
 62→    const velocityRef = useRef(0);
 63→    const starsRef = useRef([]);
 64→    const sortedIndicesRef = useRef([]);
 65→    const keysRef = useRef({ w: false, s: false, a: false, d: false, q: false, e: false });
 66→    const targetIndexRef = useRef(-1);
 67→    const frameRef = useRef(0);
 68→    const layerRef = useRef(null);
 69→    const rafRef = useRef(null);
 70→    const stageSizeRef = useRef({ width: 0, height: 0 });
 71→    const onKeyDownRef = useRef(null);
 72→    const onKeyUpRef = useRef(null);
 73→
 74→    // ── Docking refs ──────────────────────────────────────────────────
 75→    const dockingStateRef = useRef('none'); // 'none' | 'magnet' | 'approaching' | 'flash' | 'done'
 76→    const dockingTargetIdxRef = useRef(-1);
 77→    const dockingProgressRef = useRef(0);
 78→    const dockingStartTimeRef = useRef(0);
 79→    const dockingCallbackRef = useRef(null);
 80→    const inputFrozenRef = useRef(false);
 81→    const dockingStarScaleRef = useRef(1);
 82→
 83→    const sortStars = useCallback(() => {
 84→        const stars = starsRef.current;
 85→        const indices = sortedIndicesRef.current;
 86→        // Insertion sort — fast for nearly-sorted arrays, sort by viewZ descending (far first)
 87→        for (let i = 1; i < indices.length; i++) {
 88→            const key = indices[i];
 89→            let j = i - 1;
 90→            while (j >= 0 && stars[indices[j]].viewZ < stars[key].viewZ) {
 91→                indices[j + 1] = indices[j];
 92→                j--;
 93→            }
 94→            indices[j + 1] = key;
 95→        }
 96→    }, []);
 97→
 98→    const tick = useCallback(() => {
 99→        if (!isActiveRef.current) return;
100→
101→        const keys = keysRef.current;
102→        const cam = camPosRef.current;
103→        const stars = starsRef.current;
104→        const size = stageSizeRef.current;
105→        const dockState = dockingStateRef.current;
106→
107→        // ── Input processing (frozen during docking) ──────────────────
108→        if (!inputFrozenRef.current) {
109→            // ── Yaw (A/D) ─────────────────────────────────────────────
110→            if (keys.a) yawRef.current -= YAW_RATE;
111→            if (keys.d) yawRef.current += YAW_RATE;
112→
113→            // ── Pitch (Q/E), clamped ──────────────────────────────────
114→            if (keys.q) pitchRef.current = Math.min(pitchRef.current + PITCH_RATE, PITCH_MAX);
115→            if (keys.e) pitchRef.current = Math.max(pitchRef.current - PITCH_RATE, -PITCH_MAX);
116→
117→            // ── Velocity ──────────────────────────────────────────────
118→            if (keys.w) {
119→                velocityRef.current = Math.min(velocityRef.current + ACCEL, MAX_SPEED);
120→            } else if (keys.s) {
121→                velocityRef.current = Math.max(velocityRef.current - BRAKE, 0);
122→            } else {
123→                velocityRef.current *= FRICTION;
124→                if (velocityRef.current < 0.01) velocityRef.current = 0;
125→            }
126→        }
127→
128→        // ── Magnetic pull (auto-aim toward docking target) ────────────
129→        if (dockState === 'magnet') {
130→            const tidx = dockingTargetIdxRef.current;
131→            if (tidx >= 0 && tidx < stars.length) {
132→                const target = stars[tidx];
133→                const relX = target.worldX - cam.x;
134→                const relY = target.worldY - cam.y;
135→                const relZ = target.worldZ - cam.z;
136→                const dist3D = Math.sqrt(relX * relX + relY * relY + relZ * relZ);
137→                if (dist3D > 0.01) {
138→                    const desiredYaw = Math.atan2(relX, relZ);
139→                    const desiredPitch = Math.asin(Math.max(-1, Math.min(1, relY / dist3D)));
140→                    // Proximity factor: 0 at MAGNET_THRESHOLD_Z, 1 at DOCKING_THRESHOLD_Z
141→                    const proximityFactor = Math.max(0, Math.min(1,
142→                        (MAGNET_THRESHOLD_Z - target.viewZ) / (MAGNET_THRESHOLD_Z - DOCKING_THRESHOLD_Z)
143→                    ));
144→                    const lerpFactor = MAGNET_STRENGTH * (0.3 + proximityFactor * 0.7);
145→                    // Normalize yaw difference to [-PI, PI]
146→                    let yawDiff = desiredYaw - yawRef.current;
147→                    while (yawDiff > Math.PI) yawDiff -= TWO_PI;
148→                    while (yawDiff < -Math.PI) yawDiff += TWO_PI;
149→                    yawRef.current += yawDiff * lerpFactor;
150→                    pitchRef.current += (desiredPitch - pitchRef.current) * lerpFactor;
151→                    pitchRef.current = Math.max(-PITCH_MAX, Math.min(PITCH_MAX, pitchRef.current));
152→                }
153→                // Disengage if target drifts beyond magnet zone
154→                if (target.viewZ > MAGNET_THRESHOLD_Z * 1.2 || target.viewZ < TARGET_Z_MIN) {
155→                    dockingStateRef.current = 'none';
156→                    dockingTargetIdxRef.current = -1;
157→                }
158→            }
159→        }
160→
161→        // ── Docking animation sequence ────────────────────────────────
162→        if (dockState === 'approaching' || dockState === 'flash') {
163→            const elapsed = performance.now() - dockingStartTimeRef.current;
164→            const tidx = dockingTargetIdxRef.current;
165→            const target = tidx >= 0 && tidx < stars.length ? stars[tidx] : null;
166→
167→            if (elapsed < 800 && target) {
168→                // Phase 1: Auto-approach (0-800ms)
169→                const relX = target.worldX - cam.x;
170→                const relY = target.worldY - cam.y;
171→                const relZ = target.worldZ - cam.z;
172→                const dist3D = Math.sqrt(relX * relX + relY * relY + relZ * relZ);
173→                if (dist3D > 0.01) {
174→                    const desiredYaw = Math.atan2(relX, relZ);
175→                    const desiredPitch = Math.asin(Math.max(-1, Math.min(1, relY / dist3D)));
176→                    let yawDiff = desiredYaw - yawRef.current;
177→                    while (yawDiff > Math.PI) yawDiff -= TWO_PI;
178→                    while (yawDiff < -Math.PI) yawDiff += TWO_PI;
179→                    yawRef.current += yawDiff * 0.12;
180→                    pitchRef.current += (desiredPitch - pitchRef.current) * 0.12;
181→                    pitchRef.current = Math.max(-PITCH_MAX, Math.min(PITCH_MAX, pitchRef.current));
182→                }
183→                velocityRef.current = Math.min(velocityRef.current + DOCK_ACCEL, DOCK_MAX_SPEED);
184→                // Quadratic ease-in scale: 1 → 9
185→                const t1 = elapsed / 800;
186→                dockingStarScaleRef.current = 1 + 8 * t1 * t1;
187→                dockingProgressRef.current = t1 * 0.6;
188→            } else if (elapsed < 1200 && target) {
189→                // Phase 2: Star explosion (800-1200ms)
190→                velocityRef.current *= 0.9;
191→                const t2 = (elapsed - 800) / 400;
192→                // Ease-out scale: 9 → 50
193→                const easeOut = 1 - (1 - t2) * (1 - t2);
194→                dockingStarScaleRef.current = 9 + 41 * easeOut;
195→                dockingProgressRef.current = 0.6 + t2 * 0.3;
196→            } else if (elapsed < 1700) {
197→                // Phase 3: White flash (1200-1700ms)
198→                velocityRef.current = 0;
199→                dockingStateRef.current = 'flash';
200→                const t3 = (elapsed - 1200) / 500;
201→                dockingProgressRef.current = 0.9 + t3 * 0.1;
202→            } else {
203→                // Done — trigger callback
204→                dockingStateRef.current = 'done';
205→                dockingProgressRef.current = 1;
206→                if (dockingCallbackRef.current) {
207→                    dockingCallbackRef.current();
208→                }
209→            }
210→        }
211→
212→        const yaw = yawRef.current;
213→        const pitch = pitchRef.current;
214→        const velocity = velocityRef.current;
215→
216→        // ── Position (move along forward vector) ─────────────────────
217→        const fwd = getForwardVector(yaw, pitch);
218→        cam.x += fwd.x * velocity;
219→        cam.y += fwd.y * velocity;
220→        cam.z += fwd.z * velocity;
221→
222→        // ── Pre-compute trig for view transform ──────────────────────
223→        const cosYaw = Math.cos(-yaw);
224→        const sinYaw = Math.sin(-yaw);
225→        const cosPitch = Math.cos(pitch);
226→        const sinPitch = Math.sin(pitch);
227→
228→        // ── View transform + recycling ───────────────────────────────
229→        const dockingActive = dockState !== 'none';
230→        const protectedIdx = dockingTargetIdxRef.current;
231→        for (let i = 0; i < stars.length; i++) {
232→            const star = stars[i];
233→
234→            // Translate to camera-relative
235→            const relX = star.worldX - cam.x;
236→            const relY = star.worldY - cam.y;
237→            const relZ = star.worldZ - cam.z;
238→
239→            // Yaw rotation (around Y axis)
240→            const rotX1 = relX * cosYaw + relZ * sinYaw;
241→            const rotZ1 = -relX * sinYaw + relZ * cosYaw;
242→
243→            // Pitch rotation (around X axis)
244→            const rotY2 = relY * cosPitch - rotZ1 * sinPitch;
245→            const viewZ = relY * sinPitch + rotZ1 * cosPitch;
246→
247→            // Cache on star for renderer
248→            star._rotX1 = rotX1;
249→            star._rotY2 = rotY2;
250→            star.viewZ = viewZ;
251→
252→            // Recycle stars that are behind camera or too far
253→            // Skip recycling for the docking target star
254→            if ((viewZ < MIN_VIEW_Z || viewZ > RECYCLE_Z) && !(dockingActive && i === protectedIdx)) {
255→                // Respawn ahead of camera using forward vector + random spread
256→                const dist = SPAWN_DIST * (0.5 + Math.random() * 0.5);
257→                const spreadX = (Math.random() - 0.5) * 2000;
258→                const spreadY = (Math.random() - 0.5) * 2000;
259→                star.worldX = cam.x + fwd.x * dist + spreadX;
260→                star.worldY = cam.y + fwd.y * dist + spreadY;
261→                star.worldZ = cam.z + fwd.z * dist + (Math.random() - 0.5) * 1000;
262→
263→                // Recompute view-space for the recycled position
264→                const rX = star.worldX - cam.x;
265→                const rY = star.worldY - cam.y;
266→                const rZ = star.worldZ - cam.z;
267→                const rX1 = rX * cosYaw + rZ * sinYaw;
268→                const rZ1 = -rX * sinYaw + rZ * cosYaw;
269→                star._rotX1 = rX1;
270→                star._rotY2 = rY * cosPitch - rZ1 * sinPitch;
271→                star.viewZ = rY * sinPitch + rZ1 * cosPitch;
272→            }
273→        }
274→
275→        // ── Sort (every N frames) ────────────────────────────────────
276→        frameRef.current++;
277→        if (frameRef.current % SORT_INTERVAL === 0) {
278→            sortStars();
279→        }
280→
281→        // ── Target detection ─────────────────────────────────────────
282→        const cx = size.width / 2;
283→        const cy = size.height / 2;
284→        const focalLength = size.width * 0.6;
285→        let bestIdx = -1;
286→        let bestDist = TARGET_DIST_MAX;
287→
288→        for (let i = 0; i < stars.length; i++) {
289→            const star = stars[i];
290→            if (star.viewZ < TARGET_Z_MIN) continue;
291→            const projX = cx + (star._rotX1 / star.viewZ) * focalLength;
292→            const projY = cy - (star._rotY2 / star.viewZ) * focalLength;
293→            const dx = projX - cx;
294→            const dy = projY - cy;
295→            const dist = Math.sqrt(dx * dx + dy * dy);
296→            if (dist < bestDist) {
297→                bestDist = dist;
298→                bestIdx = i;
299→            }
300→        }
301→        targetIndexRef.current = bestIdx;
302→
303→        // ── Docking detection ─────────────────────────────────────────
304→        if (dockState === 'none' && bestIdx >= 0) {
305→            const targetStar = stars[bestIdx];
306→            const viewZ = targetStar.viewZ;
307→            if (viewZ < DOCKING_THRESHOLD_Z && bestDist < DOCKING_CENTER_MAX) {
308→                // Close enough and centered — auto-dock
309→                dockingStateRef.current = 'approaching';
310→                dockingTargetIdxRef.current = bestIdx;
311→                dockingStartTimeRef.current = performance.now();
312→                dockingProgressRef.current = 0;
313→                dockingStarScaleRef.current = 1;
314→                inputFrozenRef.current = true;
315→            } else if (viewZ < MAGNET_THRESHOLD_Z && viewZ > DOCKING_THRESHOLD_Z) {
316→                // In magnet zone — engage gentle pull
317→                dockingStateRef.current = 'magnet';
318→                dockingTargetIdxRef.current = bestIdx;
319→            }
320→        }
321→        // Disengage magnet if best target changes
322→        if (dockState === 'magnet' && bestIdx !== dockingTargetIdxRef.current) {
323→            dockingStateRef.current = 'none';
324→            dockingTargetIdxRef.current = -1;
325→        }
326→
327→        // ── Redraw ───────────────────────────────────────────────────
328→        if (layerRef.current) {
329→            layerRef.current.batchDraw();
330→        }
331→
332→        rafRef.current = requestAnimationFrame(tick);
333→    }, [sortStars]);
334→
335→    const enter = useCallback((galaxyPosts, galaxyCenter, stageSize) => {
336→        // Clean up any existing loop/listeners before re-entering
337→        isActiveRef.current = false;
338→        if (rafRef.current) { cancelAnimationFrame(rafRef.current); rafRef.current = null; }
339→        if (onKeyDownRef.current) {
340→            window.removeEventListener('keydown', onKeyDownRef.current);
341→            window.removeEventListener('keyup', onKeyUpRef.current);
342→            onKeyDownRef.current = null; onKeyUpRef.current = null;
343→        }
344→
345→        stageSizeRef.current = stageSize;
346→        camPosRef.current = { x: galaxyCenter.x, y: galaxyCenter.y, z: 0 };
347→        yawRef.current = 0;
348→        pitchRef.current = 0;
349→        velocityRef.current = 0;
350→        frameRef.current = 0;
351→        targetIndexRef.current = -1;
352→
353→        // Reset docking state
354→        dockingStateRef.current = 'none';
355→        dockingTargetIdxRef.current = -1;
356→        dockingProgressRef.current = 0;
357→        dockingStarScaleRef.current = 1;
358→        inputFrozenRef.current = false;
359→
360→        // Build star array from posts — distributed in 3D volume
361→        const stars = [];
362→        for (let i = 0; i < galaxyPosts.length; i++) {
363→            const post = galaxyPosts[i];
364→            const uid = post.users?.id ?? post.user_id;
365→            const likeCount = post.like_count != null
366→                ? post.like_count
367→                : (Array.isArray(post.likes) && post.likes[0]?.count != null
368→                    ? post.likes[0].count : 0);
369→            const color = getStarColor(uid);
370→            const rng = seededRandom(simpleHash(post.id || String(i)));
371→            stars.push({
372→                postId: post.id,
373→                worldX: post.universe_x ?? post.display_x ?? galaxyCenter.x + (rng() - 0.5) * 2000,
374→                worldY: post.universe_y ?? post.display_y ?? galaxyCenter.y + (rng() - 0.5) * 2000,
375→                worldZ: (rng() - 0.5) * SPAWN_DIST * 2, // ±SPAWN_DIST from camera z=0
376→                viewZ: 0,
377→                _rotX1: 0,
378→                _rotY2: 0,
379→                color,
380→                colorRgb: parseHex(color),
381→                radius: getStarRadius(likeCount),
382→                title: post.title || 'Untitled',
383→                authorName: post.users?.name || post.user_name || 'Anonymous',
384→                post,
385→            });
386→        }
387→
388→        starsRef.current = stars;
389→
390→        // Build sorted indices (far → near by viewZ, will be sorted properly on first tick)
391→        const indices = new Array(stars.length);
392→        for (let i = 0; i < stars.length; i++) indices[i] = i;
393→        sortedIndicesRef.current = indices;
394→
395→        // Key listeners
396→        const onKeyDown = (e) => {
397→            const key = e.key.toLowerCase();
398→            if (key === 'w') keysRef.current.w = true;
399→            if (key === 's') keysRef.current.s = true;
400→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = true;
401→            if (key === 'd' || key === 'arrowright') keysRef.current.d = true;
402→            if (key === 'q' || key === 'arrowup') keysRef.current.q = true;
403→            if (key === 'e' || key === 'arrowdown') keysRef.current.e = true;
404→        };
405→        const onKeyUp = (e) => {
406→            const key = e.key.toLowerCase();
407→            if (key === 'w') keysRef.current.w = false;
408→            if (key === 's') keysRef.current.s = false;
409→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = false;
410→            if (key === 'd' || key === 'arrowright') keysRef.current.d = false;
411→            if (key === 'q' || key === 'arrowup') keysRef.current.q = false;
412→            if (key === 'e' || key === 'arrowdown') keysRef.current.e = false;
413→        };
414→
415→        onKeyDownRef.current = onKeyDown;
416→        onKeyUpRef.current = onKeyUp;
417→        window.addEventListener('keydown', onKeyDown);
418→        window.addEventListener('keyup', onKeyUp);
419→
420→        // Reset keys
421→        keysRef.current = { w: false, s: false, a: false, d: false, q: false, e: false };
422→        isActiveRef.current = true;
423→
424→        // Start rAF
425→        rafRef.current = requestAnimationFrame(tick);
426→    }, [tick]);
427→
428→    const exit = useCallback(() => {
429→        isActiveRef.current = false;
430→        if (rafRef.current) {
431→            cancelAnimationFrame(rafRef.current);
432→            rafRef.current = null;
433→        }
434→        // Remove key listeners
435→        if (onKeyDownRef.current) {
436→            window.removeEventListener('keydown', onKeyDownRef.current);
437→            window.removeEventListener('keyup', onKeyUpRef.current);
438→            onKeyDownRef.current = null;
439→            onKeyUpRef.current = null;
440→        }
441→        keysRef.current = { w: false, s: false, a: false, d: false, q: false, e: false };
442→        // Reset docking
443→        dockingStateRef.current = 'none';
444→        dockingTargetIdxRef.current = -1;
445→        dockingProgressRef.current = 0;
446→        dockingStarScaleRef.current = 1;
447→        inputFrozenRef.current = false;
448→    }, []);
449→
450→    const project = useCallback((star, cx, cy) => {
451→        if (star.viewZ <= MIN_VIEW_Z) return null; // behind camera
452→
453→        const stageWidth = stageSizeRef.current.width;
454→        const focalLength = stageWidth * 0.6; // ~80° FOV
455→        const projX = cx + (star._rotX1 / star.viewZ) * focalLength;
456→        const projY = cy - (star._rotY2 / star.viewZ) * focalLength; // negate Y for screen coords
457→        const scale = focalLength / star.viewZ;
458→
459→        return { projX, projY, scale };
460→    }, []);
461→
462→    const getTargetedPost = useCallback(() => {
463→        const idx = targetIndexRef.current;
464→        if (idx < 0 || idx >= starsRef.current.length) return null;
465→        return starsRef.current[idx].post;
466→    }, []);
467→
468→    const getSpeedRatio = useCallback(() => {
469→        return velocityRef.current / MAX_SPEED;
470→    }, []);
471→
472→    const getDockingState = useCallback(() => {
473→        return dockingStateRef.current;
474→    }, []);
475→
476→    const getSessionSnapshot = useCallback(() => {
477→        const cam = camPosRef.current;
478→        return {
479→            camX: cam.x,
480→            camY: cam.y,
481→            camZ: cam.z,
482→            yaw: yawRef.current,
483→            pitch: pitchRef.current,
484→            velocity: velocityRef.current,
485→            timestamp: Date.now(),
486→        };
487→    }, []);
488→
489→    const restoreFromSnapshot = useCallback((snapshot, galaxyPosts, stageSize) => {
490→        // Clean up any existing loop/listeners before restoring
491→        isActiveRef.current = false;
492→        if (rafRef.current) { cancelAnimationFrame(rafRef.current); rafRef.current = null; }
493→        if (onKeyDownRef.current) {
494→            window.removeEventListener('keydown', onKeyDownRef.current);
495→            window.removeEventListener('keyup', onKeyUpRef.current);
496→            onKeyDownRef.current = null; onKeyUpRef.current = null;
497→        }
498→
499→        stageSizeRef.current = stageSize;
500→        camPosRef.current = { x: snapshot.camX, y: snapshot.camY, z: snapshot.camZ };
501→        yawRef.current = snapshot.yaw;
502→        pitchRef.current = snapshot.pitch;
503→        velocityRef.current = 0; // smooth re-entry
504→        frameRef.current = 0;
505→        targetIndexRef.current = -1;
506→
507→        // Reset docking state
508→        dockingStateRef.current = 'none';
509→        dockingTargetIdxRef.current = -1;
510→        dockingProgressRef.current = 0;
511→        dockingStarScaleRef.current = 1;
512→        inputFrozenRef.current = false;
513→
514→        // Build star array (same logic as enter)
515→        const galaxyCenter = { x: snapshot.camX, y: snapshot.camY };
516→        const stars = [];
517→        for (let i = 0; i < galaxyPosts.length; i++) {
518→            const post = galaxyPosts[i];
519→            const uid = post.users?.id ?? post.user_id;
520→            const likeCount = post.like_count != null
521→                ? post.like_count
